import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const formatDate = (d) => {
  if (!d) return "";
  return new Date(d).toLocaleDateString("en-IN", {
    day: "2-digit", month: "short", year: "numeric"
  });
};

const statusStyle = (s) => {
  if (s === "accepted") return "bg-green-100 text-green-700 border-green-200";
  if (s === "rejected") return "bg-red-100 text-red-600 border-red-200";
  return "bg-yellow-100 text-yellow-700 border-yellow-200";
};

const statusIcon = (s) => {
  if (s === "accepted") return "✅";
  if (s === "rejected") return "❌";
  return "⏳";
};

const MyProposals = () => {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading]     = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await API.get("/proposals/my");
        setProposals(res.data || []);
      } catch (err) {
        console.error(err);
      }
      setLoading(false);
    };
    fetch();
  }, []);

  if (loading) return <div className="text-center py-10 text-gray-500">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-3xl mx-auto">
        <h1 className="text-2xl font-bold text-gray-800 mb-1">My Proposals</h1>
        <p className="text-gray-500 mb-6 text-sm">Track all proposals you have submitted</p>

        {proposals.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center shadow">
            <div className="text-5xl mb-3">📄</div>
            <p className="text-gray-500 mb-4">No proposals submitted yet.</p>
            <button onClick={() => navigate("/freelancer/find-projects")}
              className="bg-teal-600 text-white px-5 py-2 rounded-lg text-sm font-medium">
              Find Projects →
            </button>
          </div>
        ) : (
          <div className="space-y-4">
            {proposals.map((p) => (
              <div key={p.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-5 hover:shadow-md transition">
                <div className="flex justify-between items-start mb-3">
                  <div>
                    <h3 className="font-bold text-gray-800 text-lg">{p.project_title}</h3>
                    <p className="text-gray-500 text-sm mt-0.5">{p.message}</p>
                  </div>
                  {/* ✅ Status badge */}
                  <span className={`px-3 py-1 rounded-full text-xs font-semibold capitalize border ${statusStyle(p.status)}`}>
                    {statusIcon(p.status)} {p.status || "pending"}
                  </span>
                </div>

                {/* ✅ Date fixed */}
                <div className="flex flex-wrap gap-5 text-sm mt-3 pt-3 border-t border-gray-100">
                  <span className="text-teal-600 font-bold">Your Bid: ₹{p.bid}</span>
                  <span className="text-gray-500">Project Budget: ₹{p.project_budget || "—"}</span>
                  <span className="text-gray-400">{formatDate(p.created_at)}</span>
                  {p.project_deadline && (
                    <span className="text-gray-400">📅 Due: {formatDate(p.project_deadline)}</span>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyProposals;
